@l-flame this will work if you add a target. Without a target, your rule is not complete.

    #!/usr/bin/env python
    
    import iptc
    
    def get_def_rule():
        rule = iptc.Rule()
        rule.in_interface = "eth0"
        rule.src = "192.168.1.0/255.255.255.0"
        rule.protocol = "tcp"
        rule.create_target("ACCEPT")
        return rule
    
    table = iptc.Table('filter')
    chain = iptc.Chain(table, 'INPUT')
    for rule in chain.rules:
        if rule == get_def_rule():
            print 'Matched'

HTH

